// ─────────────────────────────────────────────────────────────
// SCAN VAULT FOR OVERDUE TASKS
// Recursively reads all .md files in the vault, finds tasks
// matching: - [ ] ... [due:: YYYY-MM-DD] where due < today.
// ─────────────────────────────────────────────────────────────
const fs = require('fs');
const path = require('path');

const vaultPath = $env.OBSIDIAN_VAULT_PATH || 'C:/Users/Admin/Desktop/Desktop Folders/Obsidian/Homelab';

const now = new Date();
const todayStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
const todayDate = new Date(todayStr + 'T00:00:00');

// Recursively collect all .md files
function getMarkdownFiles(dir) {
  let results = [];
  try {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      // Skip hidden directories and .obsidian
      if (entry.name.startsWith('.')) continue;
      if (entry.name === 'node_modules') continue;
      if (entry.isDirectory()) {
        results = results.concat(getMarkdownFiles(fullPath));
      } else if (entry.isFile() && entry.name.endsWith('.md')) {
        results.push(fullPath);
      }
    }
  } catch (err) {
    // Skip directories that can't be read
  }
  return results;
}

const taskPattern = /^\s*- \[ \]\s+(.+)$/gm;
const duePattern = /\[due::\s*(\d{4}-\d{2}-\d{2})\s*\]/;
const areaPattern = /\[area::\s*(\w+)\s*\]/;
const priorityPattern = /\[priority::\s*([A-C])\s*\]/;

const overdueTasks = [];
const mdFiles = getMarkdownFiles(vaultPath);

for (const filePath of mdFiles) {
  try {
    const content = fs.readFileSync(filePath, 'utf8');
    let match;

    // Reset regex lastIndex
    taskPattern.lastIndex = 0;

    while ((match = taskPattern.exec(content)) !== null) {
      const taskLine = match[1];
      const dueMatch = taskLine.match(duePattern);

      if (!dueMatch) continue;

      const dueDateStr = dueMatch[1];
      const dueDate = new Date(dueDateStr + 'T00:00:00');

      if (dueDate >= todayDate) continue;

      // This task is overdue
      const areaMatch = taskLine.match(areaPattern);
      const priorityMatch = taskLine.match(priorityPattern);

      // Extract clean task title (remove inline fields)
      const cleanTitle = taskLine
        .replace(/\[area::\s*\w+\s*\]/g, '')
        .replace(/\[priority::\s*[A-C]\s*\]/g, '')
        .replace(/\[due::\s*\d{4}-\d{2}-\d{2}\s*\]/g, '')
        .replace(/\s{2,}/g, ' ')
        .trim();

      const relativePath = path.relative(vaultPath, filePath).replace(/\\/g, '/');

      overdueTasks.push({
        title: cleanTitle,
        area: areaMatch ? areaMatch[1] : 'unknown',
        priority: priorityMatch ? priorityMatch[1] : 'none',
        due: dueDateStr,
        daysOverdue: Math.floor((todayDate.getTime() - dueDate.getTime()) / 86400000),
        sourceFile: relativePath
      });
    }
  } catch (err) {
    // Skip files that can't be read
    continue;
  }
}

// Sort by priority (A first), then by days overdue (most overdue first)
overdueTasks.sort((a, b) => {
  const priorityOrder = { 'A': 0, 'B': 1, 'C': 2, 'none': 3 };
  const pDiff = (priorityOrder[a.priority] || 3) - (priorityOrder[b.priority] || 3);
  if (pDiff !== 0) return pDiff;
  return b.daysOverdue - a.daysOverdue;
});

return [{
  json: {
    todayStr,
    totalOverdue: overdueTasks.length,
    tasks: overdueTasks,
    hasOverdue: overdueTasks.length > 0
  }
}];

// ─────────────────────────────────────────────────────────────
// FORMAT OVERDUE TASKS SUMMARY
// Groups tasks by area, counts by priority, builds a markdown
// summary suitable for notification delivery.
// ─────────────────────────────────────────────────────────────
const { todayStr, totalOverdue, tasks } = $input.item.json;

// Group by area
const byArea = {};
for (const task of tasks) {
  const area = task.area || 'unknown';
  if (!byArea[area]) byArea[area] = [];
  byArea[area].push(task);
}

// Count by priority
const byPriority = { A: 0, B: 0, C: 0, none: 0 };
for (const task of tasks) {
  const p = task.priority || 'none';
  byPriority[p] = (byPriority[p] || 0) + 1;
}

// Build markdown summary
let md = `# Overdue Task Alert -- ${todayStr}\n\n`;
md += `**${totalOverdue} overdue task${totalOverdue !== 1 ? 's' : ''} found.**\n\n`;

// Priority breakdown
md += `### Priority Breakdown\n`;
if (byPriority.A > 0) md += `- **Priority A (Urgent):** ${byPriority.A}\n`;
if (byPriority.B > 0) md += `- **Priority B (Important):** ${byPriority.B}\n`;
if (byPriority.C > 0) md += `- **Priority C (Backlog):** ${byPriority.C}\n`;
if (byPriority.none > 0) md += `- **No Priority:** ${byPriority.none}\n`;
md += `\n`;

// Tasks by area
md += `### Tasks by Area\n\n`;
const areaNames = Object.keys(byArea).sort();
for (const area of areaNames) {
  const areaTasks = byArea[area];
  md += `#### ${area.charAt(0).toUpperCase() + area.slice(1)} (${areaTasks.length})\n\n`;
  for (const t of areaTasks) {
    const priorityTag = t.priority !== 'none' ? ` [${t.priority}]` : '';
    md += `- ${t.title}${priorityTag} -- due ${t.due} (${t.daysOverdue}d overdue)\n`;
  }
  md += `\n`;
}

// Most critical (top 5 priority-A tasks)
const criticalTasks = tasks.filter(t => t.priority === 'A').slice(0, 5);
if (criticalTasks.length > 0) {
  md += `### Most Critical\n\n`;
  for (const t of criticalTasks) {
    md += `- **${t.title}** -- ${t.daysOverdue}d overdue (${t.sourceFile})\n`;
  }
  md += `\n`;
}

return [{
  json: {
    todayStr,
    totalOverdue,
    byPriority,
    areaCount: areaNames.length,
    summary: md,
    hasOverdue: true
  }
}];

// ─────────────────────────────────────────────────────────────
// ALL CLEAR: No overdue tasks
// Generates a positive 'all clear' message for notification.
// ─────────────────────────────────────────────────────────────
const { todayStr } = $input.item.json;

const md = `# Overdue Task Alert -- ${todayStr}\n\nAll clear! No overdue tasks found. Great job staying on top of things.\n`;

return [{
  json: {
    todayStr,
    totalOverdue: 0,
    summary: md,
    hasOverdue: false
  }
}];

// ─────────────────────────────────────────────────────────────
// COMPLETION SUMMARY
// Logs the final result of the overdue task scan and notification.
// ─────────────────────────────────────────────────────────────
const webhookResponse = $input.item.json;

// Pull data from earlier nodes
let summaryData;
try {
  summaryData = $('Format Summary').item.json;
} catch (e) {
  try {
    summaryData = $('All Clear Message').item.json;
  } catch (e2) {
    summaryData = { todayStr: new Date().toISOString().slice(0, 10), totalOverdue: 0 };
  }
}

const webhookStatus = webhookResponse.statusCode || 'unknown';
const webhookSuccess = webhookResponse.statusCode && webhookResponse.statusCode >= 200 && webhookResponse.statusCode < 300;

const summary = {
  timestamp: new Date().toISOString(),
  date: summaryData.todayStr,
  totalOverdue: summaryData.totalOverdue,
  notificationSent: webhookSuccess,
  webhookStatus: webhookStatus,
  message: webhookSuccess
    ? `Notification sent successfully. ${summaryData.totalOverdue} overdue task(s) reported.`
    : `Notification delivery may have failed (HTTP ${webhookStatus}). ${summaryData.totalOverdue} overdue task(s) found.`
};

console.log(`Overdue Task Alert: ${summary.message}`);

return [{ json: summary }];
